contracts/NexaloStaking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

interface INXLToken is IERC20 {
    function balanceOf(address account) external view returns (uint256);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function transfer(address to, uint256 amount) external returns (bool);
}

/**
 * @title NexaloStaking
 * @dev Staking de NXL con rewards en BTC (WBTC)
 * 
 * CARACTERÍSTICAS:
 * - Stake NXL, recibe WBTC como reward
 * - APY: 3-5% anual
 * - Sin lock-up (puedes retirar cuando quieras)
 * - Rewards acumulados se calculan por segundo
 * - Integración con AAVE (en v2 se conecta pool real)
 */
contract NexaloStaking is ReentrancyGuard, Ownable {
    
    // ========== TOKENS ==========
    INXLToken public immutable nxlToken;
    IERC20 public immutable wbtc; // Wrapped Bitcoin
    
    // ========== APY Y REWARDS ==========
    uint256 public constant APY_RATE = 400; // 4% anual (base 10000)
    uint256 public constant SECONDS_PER_YEAR = 365 days;
    
    // ========== STAKING DATA ==========
    struct Stake {
        uint256 amount;           // NXL staked
        uint256 startTime;        // Cuando hizo stake
        uint256 lastClaimTime;    // Última vez que reclamó rewards
        uint256 totalClaimed;     // Total WBTC reclamado histórico
    }
    
    mapping(address => Stake) public stakes;
    
    // ========== ESTADÍSTICAS GLOBALES ==========
    uint256 public totalStaked;
    uint256 public totalRewardsPaid;
    uint256 public totalStakers;
    
    // ========== EVENTOS ==========
    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 amount);
    event RewardsFunded(address indexed funder, uint256 amount);
    
    // ========== CONSTRUCTOR ==========
    constructor(
        address _nxlToken,
        address _wbtc
    ) Ownable(msg.sender) {
        require(_nxlToken != address(0), "Invalid NXL token");
        require(_wbtc != address(0), "Invalid WBTC");
        
        nxlToken = INXLToken(_nxlToken);
        wbtc = IERC20(_wbtc);
    }
    
    // ========== STAKING ==========
    
    /**
     * @dev Hacer stake de NXL
     */
    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be > 0");
        require(
            nxlToken.balanceOf(msg.sender) >= amount,
            "Insufficient NXL balance"
        );
        
        // Si ya tiene stake, reclamar rewards primero
        if (stakes[msg.sender].amount > 0) {
            _claimRewards(msg.sender);
        }
        
        // Transferir NXL al contrato
        require(
            nxlToken.transferFrom(msg.sender, address(this), amount),
            "Transfer failed"
        );
        
        // Actualizar stake
        if (stakes[msg.sender].amount == 0) {
            totalStakers++;
            stakes[msg.sender] = Stake({
                amount: amount,
                startTime: block.timestamp,
                lastClaimTime: block.timestamp,
                totalClaimed: 0
            });
        } else {
            stakes[msg.sender].amount += amount;
        }
        
        totalStaked += amount;
        
        emit Staked(msg.sender, amount);
    }
    
    /**
     * @dev Retirar NXL (unstake)
     */
    function unstake(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be > 0");
        require(stakes[msg.sender].amount >= amount, "Insufficient staked");
        
        // Reclamar rewards antes de retirar
        _claimRewards(msg.sender);
        
        // Actualizar stake
        stakes[msg.sender].amount -= amount;
        totalStaked -= amount;
        
        if (stakes[msg.sender].amount == 0) {
            totalStakers--;
        }
        
        // Devolver NXL
        require(
            nxlToken.transfer(msg.sender, amount),
            "Transfer failed"
        );
        
        emit Unstaked(msg.sender, amount);
    }
    
    /**
     * @dev Reclamar rewards acumulados
     */
    function claimRewards() external nonReentrant {
        require(stakes[msg.sender].amount > 0, "No stake found");
        _claimRewards(msg.sender);
    }
    
    /**
     * @dev Reclamar rewards interno
     */
    function _claimRewards(address user) private {
        uint256 pending = calculatePendingRewards(user);
        
        if (pending > 0) {
            require(
                wbtc.balanceOf(address(this)) >= pending,
                "Insufficient WBTC in contract"
            );
            
            stakes[user].lastClaimTime = block.timestamp;
            stakes[user].totalClaimed += pending;
            totalRewardsPaid += pending;
            
            require(wbtc.transfer(user, pending), "WBTC transfer failed");
            
            emit RewardsClaimed(user, pending);
        }
    }
    
    // ========== CÁLCULO DE REWARDS ==========
    
    /**
     * @dev Calcular rewards pendientes de un usuario
     * Formula: (nxlStaked * APY * timeStaked) / (SECONDS_PER_YEAR * 10000)
     */
    function calculatePendingRewards(address user) public view returns (uint256) {
        Stake memory userStake = stakes[user];
        
        if (userStake.amount == 0) return 0;
        
        uint256 timeStaked = block.timestamp - userStake.lastClaimTime;
        
        // Rewards en NXL value
        uint256 rewardsInNXL = (userStake.amount * APY_RATE * timeStaked) / (SECONDS_PER_YEAR * 10000);
        
        // Convertir a WBTC
        // Asumiendo: 1 NXL = $0.05, 1 WBTC = $50,000
        // 1 WBTC = 1,000,000 NXL
        // rewardsInWBTC = rewardsInNXL / 1,000,000
        // WBTC tiene 8 decimales, NXL tiene 18
        uint256 rewardsInWBTC = (rewardsInNXL * 1e8) / (1_000_000 * 1e18);
        
        return rewardsInWBTC;
    }
    
    /**
     * @dev Calcular APY actual (puede variar según pool WBTC)
     */
    function getCurrentAPY() external pure returns (uint256) {
        return APY_RATE; // 400 = 4%
    }
    
    // ========== FONDEO DE REWARDS ==========
    
    /**
     * @dev Fondear contrato con WBTC para pagar rewards
     */
    function fundRewards(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be > 0");
        require(
            wbtc.transferFrom(msg.sender, address(this), amount),
            "WBTC transfer failed"
        );
        
        emit RewardsFunded(msg.sender, amount);
    }
    
    // ========== VISTAS PÚBLICAS ==========
    
    /**
     * @dev Información de stake de un usuario
     */
    function getStakeInfo(address user) external view returns (
        uint256 stakedAmount,
        uint256 pendingRewards,
        uint256 totalClaimed,
        uint256 stakingDuration
    ) {
        Stake memory userStake = stakes[user];
        uint256 pending = calculatePendingRewards(user);
        uint256 duration = userStake.amount > 0 ? block.timestamp - userStake.startTime : 0;
        
        return (
            userStake.amount,
            pending,
            userStake.totalClaimed,
            duration
        );
    }
    
    /**
     * @dev Estadísticas globales
     */
    function getGlobalStats() external view returns (
        uint256 _totalStaked,
        uint256 _totalStakers,
        uint256 _totalRewardsPaid,
        uint256 _wbtcBalance,
        uint256 _apy
    ) {
        return (
            totalStaked,
            totalStakers,
            totalRewardsPaid,
            wbtc.balanceOf(address(this)),
            APY_RATE
        );
    }
    
    /**
     * @dev Calcular rewards estimados por periodo
     */
    function estimateRewards(uint256 nxlAmount, uint256 days_) external pure returns (uint256) {
        uint256 timeInSeconds = days_ * 1 days;
        uint256 rewardsInNXL = (nxlAmount * APY_RATE * timeInSeconds) / (SECONDS_PER_YEAR * 10000);
        uint256 rewardsInWBTC = (rewardsInNXL * 1e8) / (1_000_000 * 1e18);
        
        return rewardsInWBTC;
    }
    
    // ========== ADMIN ==========
    
    /**
     * @dev Retirar exceso de WBTC (solo owner)
     */
    function withdrawExcess(uint256 amount) external onlyOwner nonReentrant {
        require(amount > 0, "Amount must be > 0");
        require(wbtc.balanceOf(address(this)) >= amount, "Insufficient balance");
        
        require(wbtc.transfer(owner(), amount), "Transfer failed");
    }
    
    /**
     * @dev Recuperar tokens enviados por error
     */
    function recoverTokens(address token, uint256 amount) external onlyOwner {
        require(token != address(nxlToken), "Cannot recover NXL");
        require(token != address(wbtc), "Cannot recover WBTC (use withdrawExcess)");
        
        IERC20(token).transfer(owner(), amount);
    }
    
    /**
     * @dev Pausa de emergencia
     */
    bool public paused;
    
    function pause() external onlyOwner {
        paused = true;
    }
    
    function unpause() external onlyOwner {
        paused = false;
    }
    
    modifier whenNotPaused() {
        require(!paused, "Contract paused");
        _;
    }
}

contracts/NexumManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@chainlink/contracts/src/v0.8/vrf/VRFConsumerBaseV2.sol";
import "@chainlink/contracts/src/v0.8/interfaces/VRFCoordinatorV2Interface.sol";

interface INXLToken {
    function distributeReward(address recipient, uint256 amount) external;
    function burnUndistributed(uint256 amount) external;
    function balanceOf(address account) external view returns (uint256);
}

interface IReferralNetwork {
    function setReferrer(address user, address referrer) external;
    function distributeCommissions(address buyer, uint256 amount) external;
    function hasReferrer(address user) external view returns (bool);
}

interface IAmbassadorRegistry {
    function distributeFunds() external;
}

contract NexumManager is VRFConsumerBaseV2, ReentrancyGuard, Ownable {
    
    struct NexumProduct {
        string name;
        uint256 priceUSD;
        uint256 maxTickets;
        uint256 nxlPerTicket;
        uint256 nxlWinnerBonus;
        uint256 jackpotUSD;
        bool active;
    }
    
    struct Round {
        uint256 productId;
        uint256 roundId;
        uint256 ticketsSold;
        uint256 totalCollected;
        address winner;
        bool completed;
        bool vrfRequested;
        uint256 vrfRequestId;
    }
    
    IERC20 public immutable stablecoin;
    INXLToken public immutable nxlToken;
    address public immutable founder;
    address public immutable partner;
    
    address public treasuryBTC;
    address public referralNetwork;
    address public ambassadorRegistry;
    address public buybackContract;
    address public auditFunds;
    
    VRFCoordinatorV2Interface public immutable vrfCoordinator;
    uint64 public immutable subscriptionId;
    bytes32 public immutable keyHash;
    uint32 public callbackGasLimit = 200000;
    uint16 public constant REQUEST_CONFIRMATIONS = 3;
    uint32 public constant NUM_WORDS = 1;
    
    mapping(uint256 => NexumProduct) public products;
    uint256 public constant PRODUCT_COUNT = 6;
    
    mapping(uint256 => mapping(uint256 => Round)) public rounds;
    mapping(uint256 => uint256) public currentRound;
    
    mapping(uint256 => mapping(uint256 => mapping(uint256 => address))) public ticketOwner;
    mapping(uint256 => mapping(uint256 => mapping(address => uint256[]))) public userTickets;
    
    mapping(uint256 => uint256) public vrfRequestToProduct;
    mapping(uint256 => uint256) public vrfRequestToRound;
    
    uint256 public constant MAIN_PRIZE_PCT = 5000;
    uint256 public constant INSTANT_REWARDS_PCT = 1000;
    uint256 public constant MULTILEVEL_PCT = 1000;
    uint256 public constant TREASURY_BTC_PCT = 1000;
    uint256 public constant AMBASSADORS_PCT = 500;
    uint256 public constant OPERATIONS_PCT = 1500;
    
    uint256 public constant FOUNDER_SHARE = 667;
    uint256 public constant AUDIT_SHARE = 133;
    uint256 public constant PARTNER_SHARE = 67;
    uint256 public constant FEES_SHARE = 133;
    
    bool public paused;
    
    event TicketsPurchased(uint256 indexed productId, uint256 indexed roundId, address indexed buyer, uint256 quantity, uint256[] ticketNumbers, uint256 amountPaid);
    event RoundCompleted(uint256 indexed productId, uint256 indexed roundId, address indexed winner, uint256 prize, uint256 winningTicket);
    event NewRoundStarted(uint256 indexed productId, uint256 indexed roundId, uint256 timestamp);
    event VRFRequested(uint256 indexed requestId, uint256 indexed productId, uint256 indexed roundId);
    event NXLRewardsExhausted(uint256 indexed productId);
    event ProductReactivated(uint256 indexed productId);
    event AuditFundsTransferred(address indexed to, uint256 amount);
    
    modifier whenNotPaused() {
        require(!paused, "Contract paused");
        _;
    }
    
    modifier validProduct(uint256 productId) {
        require(productId < PRODUCT_COUNT, "Invalid product");
        require(products[productId].active, "Product inactive");
        _;
    }
    
    constructor(
        address _vrfCoordinator,
        uint64 _subscriptionId,
        bytes32 _keyHash,
        address _stablecoin,
        address _nxlToken,
        address _founder,
        address _partner
    ) VRFConsumerBaseV2(_vrfCoordinator) Ownable(msg.sender) {
        require(_stablecoin != address(0), "Invalid stablecoin");
        require(_nxlToken != address(0), "Invalid NXL token");
        require(_founder != address(0), "Invalid founder");
        require(_partner != address(0), "Invalid partner");
        
        vrfCoordinator = VRFCoordinatorV2Interface(_vrfCoordinator);
        subscriptionId = _subscriptionId;
        keyHash = _keyHash;
        stablecoin = IERC20(_stablecoin);
        nxlToken = INXLToken(_nxlToken);
        founder = _founder;
        partner = _partner;
        auditFunds = _founder;
        
        _initializeProducts();
        
        for (uint256 i = 0; i < PRODUCT_COUNT; i++) {
            currentRound[i] = 1;
            emit NewRoundStarted(i, 1, block.timestamp);
        }
    }
    
    function _initializeProducts() private {
        products[0] = NexumProduct("FLASH", 1 * 10**18, 1000, 0.1 * 10**18, 0.1 * 10**18, 500 * 10**18, true);
        products[1] = NexumProduct("ORIGINAL", 1 * 10**18, 10000, 0.25 * 10**18, 0.25 * 10**18, 5000 * 10**18, true);
        products[2] = NexumProduct("PREMIUM", 20 * 10**18, 1000, 0.5 * 10**18, 0.5 * 10**18, 10000 * 10**18, true);
        products[3] = NexumProduct("ELITE", 10 * 10**18, 10000, 0.55 * 10**18, 0.55 * 10**18, 50000 * 10**18, true);
        products[4] = NexumProduct("VIP", 200 * 10**18, 1000, 0.85 * 10**18, 0.85 * 10**18, 100000 * 10**18, true);
        products[5] = NexumProduct("BLACKBLOK", 200 * 10**18, 10000, 1 * 10**18, 1 * 10**18, 1000000 * 10**18, true);
    }
    
    function setEcosystemAddresses(
        address _treasuryBTC,
        address _referralNetwork,
        address _ambassadorRegistry,
        address _buybackContract
    ) external onlyOwner {
        require(treasuryBTC == address(0), "Already set");
        require(
            _treasuryBTC != address(0) &&
            _referralNetwork != address(0) &&
            _ambassadorRegistry != address(0) &&
            _buybackContract != address(0),
            "Invalid addresses"
        );
        
        treasuryBTC = _treasuryBTC;
        referralNetwork = _referralNetwork;
        ambassadorRegistry = _ambassadorRegistry;
        buybackContract = _buybackContract;
    }
    
    function buySpecificTickets(
        uint256 productId,
        uint256[] calldata ticketNumbers,
        address referrer
    ) external nonReentrant whenNotPaused validProduct(productId) {
        uint256 roundId = currentRound[productId];
        Round storage round = rounds[productId][roundId];
        NexumProduct memory product = products[productId];
        
        require(!round.completed, "Round completed");
        require(ticketNumbers.length > 0, "Must select at least one ticket");
        require(
            ticketNumbers.length == 1 || ticketNumbers.length == 3 || 
            ticketNumbers.length == 5 || ticketNumbers.length == 10,
            "Invalid quantity (1/3/5/10)"
        );
        
        for (uint256 i = 0; i < ticketNumbers.length; i++) {
            require(ticketNumbers[i] < product.maxTickets, "Invalid ticket number");
            require(
                ticketOwner[productId][roundId][ticketNumbers[i]] == address(0), 
                "Ticket already sold"
            );
            
            for (uint256 j = i + 1; j < ticketNumbers.length; j++) {
                require(ticketNumbers[i] != ticketNumbers[j], "Duplicate ticket number");
            }
        }
        
        uint256 quantity = ticketNumbers.length;
        uint256 totalPrice = product.priceUSD * quantity;
        require(stablecoin.transferFrom(msg.sender, address(this), totalPrice), "Transfer failed");
        
        for (uint256 i = 0; i < ticketNumbers.length; i++) {
            ticketOwner[productId][roundId][ticketNumbers[i]] = msg.sender;
            userTickets[productId][roundId][msg.sender].push(ticketNumbers[i]);
        }
        
        round.ticketsSold += quantity;
        round.totalCollected += totalPrice;
        
        emit TicketsPurchased(productId, roundId, msg.sender, quantity, ticketNumbers, totalPrice);
        
        uint256 nxlAmount = product.nxlPerTicket * quantity;
        _distributeNXL(msg.sender, nxlAmount, productId);
        
        if (referrer != address(0) && referrer != msg.sender && referralNetwork != address(0)) {
            IReferralNetwork refNet = IReferralNetwork(referralNetwork);
            if (!refNet.hasReferrer(msg.sender)) {
                refNet.setReferrer(msg.sender, referrer);
            }
        }
        
        if (round.ticketsSold >= product.maxTickets) {
            _requestRandomWinner(productId, roundId);
        }
    }
    
    function buyTickets(
        uint256 productId,
        uint256 quantity,
        address referrer
    ) external nonReentrant whenNotPaused validProduct(productId) {
        require(
            quantity == 1 || quantity == 3 || quantity == 5 || quantity == 10,
            "Invalid quantity (1/3/5/10)"
        );
        
        uint256 roundId = currentRound[productId];
        Round storage round = rounds[productId][roundId];
        NexumProduct memory product = products[productId];
        
        require(!round.completed, "Round completed");
        require(round.ticketsSold + quantity <= product.maxTickets, "Not enough tickets");
        
        uint256 totalPrice = product.priceUSD * quantity;
        require(stablecoin.transferFrom(msg.sender, address(this), totalPrice), "Transfer failed");
        
        uint256[] memory assignedTickets = new uint256[](quantity);
        for (uint256 i = 0; i < quantity; i++) {
            uint256 ticketNumber = round.ticketsSold;
            ticketOwner[productId][roundId][ticketNumber] = msg.sender;
            assignedTickets[i] = ticketNumber;
            userTickets[productId][roundId][msg.sender].push(ticketNumber);
            round.ticketsSold++;
        }
        
        round.totalCollected += totalPrice;
        emit TicketsPurchased(productId, roundId, msg.sender, quantity, assignedTickets, totalPrice);
        
        uint256 nxlAmount = product.nxlPerTicket * quantity;
        _distributeNXL(msg.sender, nxlAmount, productId);
        
        if (referrer != address(0) && referrer != msg.sender && referralNetwork != address(0)) {
            IReferralNetwork refNet = IReferralNetwork(referralNetwork);
            if (!refNet.hasReferrer(msg.sender)) {
                refNet.setReferrer(msg.sender, referrer);
            }
        }
        
        if (round.ticketsSold >= product.maxTickets) {
            _requestRandomWinner(productId, roundId);
        }
    }
    
    function _distributeNXL(address recipient, uint256 amount, uint256 productId) private {
        if (amount == 0) return;
        try nxlToken.distributeReward(recipient, amount) {
        } catch {
            _handleNXLExhaustion(productId);
        }
    }
    
    function _handleNXLExhaustion(uint256 productId) private {
        products[productId].active = false;
        
        try nxlToken.burnUndistributed(nxlToken.balanceOf(address(nxlToken))) {
            emit NXLRewardsExhausted(productId);
        } catch {}
        
        bool allInactive = true;
        for (uint256 i = 0; i < PRODUCT_COUNT; i++) {
            if (products[i].active) {
                allInactive = false;
                break;
            }
        }
        
        if (allInactive && auditFunds != address(0) && auditFunds != founder) {
            uint256 auditBalance = stablecoin.balanceOf(auditFunds);
            if (auditBalance > 0) {
                try stablecoin.transferFrom(auditFunds, founder, auditBalance) {
                    emit AuditFundsTransferred(founder, auditBalance);
                } catch {}
            }
        }
    }
    
    function _requestRandomWinner(uint256 productId, uint256 roundId) private {
        Round storage round = rounds[productId][roundId];
        require(!round.vrfRequested, "VRF already requested");
        
        uint256 requestId = vrfCoordinator.requestRandomWords(
            keyHash,
            subscriptionId,
            REQUEST_CONFIRMATIONS,
            callbackGasLimit,
            NUM_WORDS
        );
        
        vrfRequestToProduct[requestId] = productId;
        vrfRequestToRound[requestId] = roundId;
        round.vrfRequested = true;
        round.vrfRequestId = requestId;
        
        emit VRFRequested(requestId, productId, roundId);
    }
    
    function fulfillRandomWords(uint256 requestId, uint256[] memory randomWords) internal override {
        uint256 productId = vrfRequestToProduct[requestId];
        uint256 roundId = vrfRequestToRound[requestId];
        Round storage round = rounds[productId][roundId];
        
        require(!round.completed, "Round already completed");
        
        uint256 winningTicket = randomWords[0] % round.ticketsSold;
        address winner = ticketOwner[productId][roundId][winningTicket];
        
        round.winner = winner;
        round.completed = true;
        
        _distributeRound(productId, roundId, winner);
        emit RoundCompleted(productId, roundId, winner, products[productId].jackpotUSD, winningTicket);
        _startNewRound(productId);
    }
    
    function _distributeRound(uint256 productId, uint256 roundId, address winner) private {
        Round storage round = rounds[productId][roundId];
        uint256 total = round.totalCollected;
        
        require(total > 0, "No funds");
        require(stablecoin.balanceOf(address(this)) >= total, "Insufficient balance");
        
        uint256 mainPrize = (total * MAIN_PRIZE_PCT) / 10000;
        _safeTransfer(winner, mainPrize);
        
        uint256 instantAmount = (total * INSTANT_REWARDS_PCT) / 10000;
        _distributeInstantRewards(productId, roundId, instantAmount);
        
        uint256 multilevelAmount = (total * MULTILEVEL_PCT) / 10000;
        if (referralNetwork != address(0)) {
            _safeTransfer(referralNetwork, multilevelAmount);
            IReferralNetwork(referralNetwork).distributeCommissions(winner, multilevelAmount);
        }
        
        uint256 treasuryAmount = (total * TREASURY_BTC_PCT) / 10000;
        if (treasuryBTC != address(0)) {
            _safeTransfer(treasuryBTC, treasuryAmount);
        }
        
        uint256 ambassadorAmount = (total * AMBASSADORS_PCT) / 10000;
        if (ambassadorRegistry != address(0)) {
            _safeTransfer(ambassadorRegistry, ambassadorAmount);
        }
        
        uint256 operationsTotal = (total * OPERATIONS_PCT) / 10000;
        
        uint256 founderAmount = (operationsTotal * FOUNDER_SHARE) / 1000;
        _safeTransfer(founder, founderAmount);
        
        uint256 auditAmount = (operationsTotal * AUDIT_SHARE) / 1000;
        _safeTransfer(auditFunds, auditAmount);
        
        uint256 partnerAmount = (operationsTotal * PARTNER_SHARE) / 1000;
        _safeTransfer(partner, partnerAmount);
        
        uint256 feesAmount = (operationsTotal * FEES_SHARE) / 1000;
        _safeTransfer(founder, feesAmount);
        
        NexumProduct memory product = products[productId];
        try nxlToken.distributeReward(winner, product.nxlWinnerBonus) {} catch {}
    }
    
    function _distributeInstantRewards(uint256 productId, uint256 roundId, uint256 totalAmount) private {
        Round storage round = rounds[productId][roundId];
        
        if (round.ticketsSold == 0) return;
        
        uint256 winnersCount = round.ticketsSold < 10 ? round.ticketsSold : 10;
        uint256 prizePerWinner = totalAmount / winnersCount;
        
        uint256 seed = uint256(keccak256(abi.encodePacked(
            blockhash(block.number - 1),
            block.timestamp,
            round.totalCollected,
            productId,
            roundId
        )));
        
        uint256 offset = seed % round.ticketsSold;
        uint256 step = round.ticketsSold / winnersCount;
        
        for (uint256 i = 0; i < winnersCount; i++) {
            uint256 ticketIndex = (offset + (i * step)) % round.ticketsSold;
            address instantWinner = ticketOwner[productId][roundId][ticketIndex];
            
            if (instantWinner != address(0)) {
                _safeTransfer(instantWinner, prizePerWinner);
            }
        }
    }
    
    function _startNewRound(uint256 productId) private {
        uint256 newRoundId = currentRound[productId] + 1;
        currentRound[productId] = newRoundId;
        emit NewRoundStarted(productId, newRoundId, block.timestamp);
    }
    
    function _safeTransfer(address to, uint256 amount) private {
        if (to != address(0) && amount > 0) {
            require(stablecoin.transfer(to, amount), "Transfer failed");
        }
    }
    
    function isTicketAvailable(
        uint256 productId,
        uint256 roundId,
        uint256 ticketNumber
    ) external view returns (bool) {
        return ticketOwner[productId][roundId][ticketNumber] == address(0);
    }
    
    function getUserTickets(
        uint256 productId,
        uint256 roundId,
        address user
    ) external view returns (uint256[] memory) {
        return userTickets[productId][roundId][user];
    }
    
    function getAvailableTickets(uint256 productId) external view returns (uint256) {
        uint256 roundId = currentRound[productId];
        Round storage round = rounds[productId][roundId];
        NexumProduct memory product = products[productId];
        
        if (round.completed) return 0;
        return product.maxTickets - round.ticketsSold;
    }
    
    function getRoundInfo(
        uint256 productId,
        uint256 roundId
    ) external view returns (
        uint256 ticketsSold,
        uint256 totalCollected,
        address winner,
        bool completed,
        bool vrfRequested
    ) {
        Round storage round = rounds[productId][roundId];
        return (
            round.ticketsSold,
            round.totalCollected,
            round.winner,
            round.completed,
            round.vrfRequested
        );
    }
    
    function getProductInfo(uint256 productId) external view returns (
        string memory name,
        uint256 priceUSD,
        uint256 maxTickets,
        uint256 nxlPerTicket,
        uint256 jackpotUSD,
        bool active
    ) {
        NexumProduct memory product = products[productId];
        return (
            product.name,
            product.priceUSD,
            product.maxTickets,
            product.nxlPerTicket,
            product.jackpotUSD,
            product.active
        );
    }
    
    function reactivateProduct(uint256 productId) external onlyOwner {
        require(productId < PRODUCT_COUNT, "Invalid product");
        require(!products[productId].active, "Already active");
        
        products[productId].active = true;
        emit ProductReactivated(productId);
    }
    
    function emergencyPause() external onlyOwner {
        paused = true;
    }
    
    function emergencyUnpause() external onlyOwner {
        paused = false;
    }
    
    function setCallbackGasLimit(uint32 _gasLimit) external onlyOwner {
        require(_gasLimit >= 100000 && _gasLimit <= 500000, "Invalid gas limit");
        callbackGasLimit = _gasLimit;
    }
    
    function emergencyWithdraw() external onlyOwner {
        uint256 balance = stablecoin.balanceOf(address(this));
        require(balance > 0, "No balance");
        _safeTransfer(owner(), balance);
    }
}

contracts/NXLToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title NXLToken
 * @notice Token ERC20 con sistema de rewards y vesting
 * @dev Supply total: 100M NXL
 *      - 96M para rewards (96%) - quedan en el contrato
 *      - 3M para Founder con vesting 2 años (3%)
 *      - 1M para Partner con vesting 1 año (1%)
 */
contract NXLToken is ERC20, Ownable {

    // ═════════════════════════════════════════════════════════
    // CONSTANTES
    // ═════════════════════════════════════════════════════════

    uint256 private constant TOTAL_SUPPLY = 100_000_000 * 10**18;        // 100M
    uint256 private constant REWARDS_POOL_AMOUNT = 96_000_000 * 10**18;  // 96M
    uint256 private constant FOUNDER_AMOUNT = 3_000_000 * 10**18;        // 3M
    uint256 private constant PARTNER_AMOUNT = 1_000_000 * 10**18;        // 1M

    uint256 private constant FOUNDER_VESTING_DURATION = 730 days;  // 2 años
    uint256 private constant PARTNER_VESTING_DURATION = 365 days;  // 1 año

    // ═════════════════════════════════════════════════════════
    // VARIABLES DE ESTADO
    // ═════════════════════════════════════════════════════════

    address public immutable founderAddress;
    address public immutable partnerAddress;
    address public nexumManager;

    uint256 public immutable deploymentTime;
    uint256 public immutable founderVestingEnd;
    uint256 public immutable partnerVestingEnd;

    uint256 public founderWithdrawn;
    uint256 public partnerWithdrawn;
    uint256 public rewardsDistributed;

    bool public nexumManagerSet;

    // ═════════════════════════════════════════════════════════
    // EVENTOS
    // ═════════════════════════════════════════════════════════

    event RewardDistributed(address indexed recipient, uint256 amount);
    event VestedTokensWithdrawn(address indexed beneficiary, uint256 amount);
    event NexumManagerSet(address indexed manager);
    event TokensBurned(uint256 amount);

    // ═════════════════════════════════════════════════════════
    // CONSTRUCTOR
    // ═════════════════════════════════════════════════════════

    constructor(
        address _founderAddress,
        address _partnerAddress
    ) ERC20("NEXALO Token", "NXL") Ownable(msg.sender) {
        require(_founderAddress != address(0), "Invalid founder address");
        require(_partnerAddress != address(0), "Invalid partner address");

        founderAddress = _founderAddress;
        partnerAddress = _partnerAddress;

        deploymentTime = block.timestamp;
        founderVestingEnd = block.timestamp + FOUNDER_VESTING_DURATION;
        partnerVestingEnd = block.timestamp + PARTNER_VESTING_DURATION;

        // Mintear supply total al contrato
        // 100M total: 96M rewards + 3M founder + 1M partner
        _mint(address(this), TOTAL_SUPPLY);
    }

    // ═════════════════════════════════════════════════════════
    // CONFIGURACIÓN
    // ═════════════════════════════════════════════════════════

    /**
     * @notice Establece la dirección del NexumManager (una sola vez)
     * @dev Solo puede llamarse una vez por el owner
     */
    function setNexumManager(address _nexumManager) external onlyOwner {
        require(!nexumManagerSet, "NexumManager already set");
        require(_nexumManager != address(0), "Invalid address");

        nexumManager = _nexumManager;
        nexumManagerSet = true;

        emit NexumManagerSet(_nexumManager);
    }

    // ═════════════════════════════════════════════════════════
    // DISTRIBUCIÓN DE REWARDS
    // ═════════════════════════════════════════════════════════

    /**
     * @notice Distribuye rewards NXL desde el pool de rewards del contrato
     * @dev Solo puede ser llamado por el NexumManager
     *      Los tokens se transfieren directamente desde el contrato
     * @param recipient Dirección del destinatario
     * @param amount Cantidad de NXL a distribuir
     */
    function distributeReward(address recipient, uint256 amount) external {
        require(msg.sender == nexumManager, "Only NexumManager");
        require(recipient != address(0), "Invalid recipient");
        require(amount > 0, "Amount must be > 0");

        // Verificar que hay suficientes tokens disponibles en rewards
        uint256 availableRewards = getAvailableRewards();
        require(availableRewards >= amount, "Insufficient rewards available");

        rewardsDistributed += amount;
        
        // Transferir desde el contrato al destinatario
        _transfer(address(this), recipient, amount);

        emit RewardDistributed(recipient, amount);
    }

    /**
     * @notice Calcula los rewards disponibles
     * @return available Cantidad de NXL disponible para distribuir como rewards
     */
    function getAvailableRewards() public view returns (uint256 available) {
        // Total en el contrato
        uint256 contractBalance = balanceOf(address(this));
        
        // Tokens reservados para vesting que aún no se han retirado
        uint256 founderReserved = FOUNDER_AMOUNT - founderWithdrawn;
        uint256 partnerReserved = PARTNER_AMOUNT - partnerWithdrawn;
        uint256 totalReserved = founderReserved + partnerReserved;
        
        // Rewards disponibles = balance del contrato - tokens reservados
        if (contractBalance > totalReserved) {
            available = contractBalance - totalReserved;
        } else {
            available = 0;
        }
    }

    // ═════════════════════════════════════════════════════════
    // VESTING
    // ═════════════════════════════════════════════════════════

    /**
     * @notice Calcula cuántos tokens puede retirar el Founder
     * @return available Tokens disponibles para retirar
     */
    function getFounderAvailable() public view returns (uint256 available) {
        if (block.timestamp < deploymentTime) return 0;

        uint256 elapsed = block.timestamp - deploymentTime;
        uint256 totalVested;

        if (elapsed >= FOUNDER_VESTING_DURATION) {
            // Vesting completo
            totalVested = FOUNDER_AMOUNT;
        } else {
            // Vesting proporcional
            totalVested = (FOUNDER_AMOUNT * elapsed) / FOUNDER_VESTING_DURATION;
        }

        available = totalVested - founderWithdrawn;
    }

    /**
     * @notice Calcula cuántos tokens puede retirar el Partner
     * @return available Tokens disponibles para retirar
     */
    function getPartnerAvailable() public view returns (uint256 available) {
        if (block.timestamp < deploymentTime) return 0;

        uint256 elapsed = block.timestamp - deploymentTime;
        uint256 totalVested;

        if (elapsed >= PARTNER_VESTING_DURATION) {
            // Vesting completo
            totalVested = PARTNER_AMOUNT;
        } else {
            // Vesting proporcional
            totalVested = (PARTNER_AMOUNT * elapsed) / PARTNER_VESTING_DURATION;
        }

        available = totalVested - partnerWithdrawn;
    }

    /**
     * @notice Founder retira tokens disponibles por vesting
     */
    function founderWithdraw() external {
        require(msg.sender == founderAddress, "Only founder");

        uint256 available = getFounderAvailable();
        require(available > 0, "No tokens available");

        founderWithdrawn += available;
        _transfer(address(this), founderAddress, available);

        emit VestedTokensWithdrawn(founderAddress, available);
    }

    /**
     * @notice Partner retira tokens disponibles por vesting
     */
    function partnerWithdraw() external {
        require(msg.sender == partnerAddress, "Only partner");

        uint256 available = getPartnerAvailable();
        require(available > 0, "No tokens available");

        partnerWithdrawn += available;
        _transfer(address(this), partnerAddress, available);

        emit VestedTokensWithdrawn(partnerAddress, available);
    }

    // ═════════════════════════════════════════════════════════
    // QUEMA DE TOKENS
    // ═════════════════════════════════════════════════════════

    /**
     * @notice Quema tokens no distribuidos del pool de rewards
     * @dev Solo puede ser llamado por el NexumManager cuando se agota el supply
     * @param amount Cantidad de tokens a quemar
     */
    function burnUndistributed(uint256 amount) external {
        require(msg.sender == nexumManager, "Only NexumManager");
        require(amount > 0, "Amount must be > 0");

        uint256 availableRewards = getAvailableRewards();
        require(availableRewards >= amount, "Insufficient balance");

        _burn(address(this), amount);

        emit TokensBurned(amount);
    }

    /**
     * @notice Permite a cualquiera quemar sus propios tokens
     * @param amount Cantidad a quemar
     */
    function burn(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");
        _burn(msg.sender, amount);

        emit TokensBurned(amount);
    }

    // ═════════════════════════════════════════════════════════
    // VISTAS
    // ═════════════════════════════════════════════════════════

    /**
     * @notice Retorna información completa del token
     */
    function getTokenInfo() external view returns (
        uint256 totalSupply_,
        uint256 contractBalance,
        uint256 availableRewards,
        uint256 rewardsDistributed_,
        uint256 founderTotal,
        uint256 founderWithdrawn_,
        uint256 founderAvailable,
        uint256 partnerTotal,
        uint256 partnerWithdrawn_,
        uint256 partnerAvailable
    ) {
        return (
            totalSupply(),
            balanceOf(address(this)),
            getAvailableRewards(),
            rewardsDistributed,
            FOUNDER_AMOUNT,
            founderWithdrawn,
            getFounderAvailable(),
            PARTNER_AMOUNT,
            partnerWithdrawn,
            getPartnerAvailable()
        );
    }

    /**
     * @notice Retorna información de vesting
     */
    function getVestingInfo() external view returns (
        uint256 founderTotal,
        uint256 founderWithdrawnAmount,
        uint256 founderAvailable,
        uint256 founderVestingEndTime,
        uint256 partnerTotal,
        uint256 partnerWithdrawnAmount,
        uint256 partnerAvailable,
        uint256 partnerVestingEndTime
    ) {
        return (
            FOUNDER_AMOUNT,
            founderWithdrawn,
            getFounderAvailable(),
            founderVestingEnd,
            PARTNER_AMOUNT,
            partnerWithdrawn,
            getPartnerAvailable(),
            partnerVestingEnd
        );
    }
}

contracts/ReferralNetwork.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title ReferralNetwork
 * @dev Sistema multinivel 3 niveles (5% + 3% + 2%)
 */
contract ReferralNetwork is Ownable, ReentrancyGuard {
    
    IERC20 public immutable stablecoin;
    
    // Niveles (base 10000 = 100%)
    uint256 public constant LEVEL1_PCT = 5000; // 50% del 10% = 5%
    uint256 public constant LEVEL2_PCT = 3000; // 30% del 10% = 3%
    uint256 public constant LEVEL3_PCT = 2000; // 20% del 10% = 2%
    
    mapping(address => address) public referrer;
    mapping(address => uint256) public totalEarned;
    mapping(address => address[]) public directReferrals;
    
    address public nexumManager;
    
    event ReferrerSet(address indexed user, address indexed referrer);
    event CommissionPaid(address indexed referrer, address indexed buyer, uint256 level, uint256 amount);
    
    constructor(address _stablecoin) Ownable(msg.sender) {
        require(_stablecoin != address(0), "Invalid stablecoin");
        stablecoin = IERC20(_stablecoin);
    }
    
    function setNexumManager(address _manager) external onlyOwner {
        require(_manager != address(0), "Invalid manager");
        require(nexumManager == address(0), "Already set");
        nexumManager = _manager;
    }
    
    modifier onlyManager() {
        require(msg.sender == nexumManager, "Only manager");
        _;
    }
    
    function setReferrer(address user, address _referrer) external onlyManager {
        require(user != address(0) && _referrer != address(0), "Invalid addresses");
        require(user != _referrer, "Cannot refer yourself");
        require(referrer[user] == address(0), "Already has referrer");
        
        // Evitar ciclos
        address current = _referrer;
        for (uint256 i = 0; i < 3; i++) {
            if (current == address(0)) break;
            require(current != user, "Referral cycle");
            current = referrer[current];
        }
        
        referrer[user] = _referrer;
        directReferrals[_referrer].push(user);
        
        emit ReferrerSet(user, _referrer);
    }
    
    function distributeCommissions(address buyer, uint256 totalAmount) external onlyManager nonReentrant {
        require(totalAmount > 0, "Invalid amount");
        
        address level1 = referrer[buyer];
        if (level1 != address(0)) {
            uint256 amount1 = (totalAmount * LEVEL1_PCT) / 10000;
            if (amount1 > 0) {
                require(stablecoin.transfer(level1, amount1), "Transfer failed");
                totalEarned[level1] += amount1;
                emit CommissionPaid(level1, buyer, 1, amount1);
            }
        }
        
        address level2 = level1 != address(0) ? referrer[level1] : address(0);
        if (level2 != address(0)) {
            uint256 amount2 = (totalAmount * LEVEL2_PCT) / 10000;
            if (amount2 > 0) {
                require(stablecoin.transfer(level2, amount2), "Transfer failed");
                totalEarned[level2] += amount2;
                emit CommissionPaid(level2, buyer, 2, amount2);
            }
        }
        
        address level3 = level2 != address(0) ? referrer[level2] : address(0);
        if (level3 != address(0)) {
            uint256 amount3 = (totalAmount * LEVEL3_PCT) / 10000;
            if (amount3 > 0) {
                require(stablecoin.transfer(level3, amount3), "Transfer failed");
                totalEarned[level3] += amount3;
                emit CommissionPaid(level3, buyer, 3, amount3);
            }
        }
    }
    
    function hasReferrer(address user) external view returns (bool) {
        return referrer[user] != address(0);
    }
    
    function getReferralChain(address user) external view returns (address level1, address level2, address level3) {
        level1 = referrer[user];
        level2 = level1 != address(0) ? referrer[level1] : address(0);
        level3 = level2 != address(0) ? referrer[level2] : address(0);
    }
}

